content.text:
/* Remove default browser markers and indent */
ul, ol {
  list-style: none;
  margin: 0;
  padding: 0;
}

/* Custom marker using a pseudo-element */
ul li::before {
  content: '→ ';
  color: #6366f1;
}

/* Alphabetical ordered list */
ol.steps {
  list-style-type: lower-alpha;
}

/* Marker inside vs outside the box model */
ul.inline-marker {
  list-style-position: inside;  /* marker inside the li's padding box */
}

// product-list.component.ts
import { Component } from '@angular/core';
import { NgFor } from '@angular/common';

interface Product {
  id: number;
  name: string;
  inStock: boolean;
}

@Component({
  selector: 'app-product-list',
  imports: [NgFor],
  template: `
    <ul>
      @for (product of products; track product.id) {
        <li [class.out-of-stock]="!product.inStock">
          {{ product.name }}
        </li>
      }
    </ul>
  `,
})
export class ProductListComponent {
  products: Product[] = [
    { id: 1, name: 'Angular Handbook', inStock: true },
    { id: 2, name: 'TypeScript Deep Dive', inStock: false },
    { id: 3, name: 'RxJS Patterns', inStock: true },
  ];
}

// framework-list.component.ts
import { Component, signal, computed } from '@angular/core';
import { FormsModule } from '@angular/forms';

interface Framework {
  id: number;
  name: string;
  language: string;
}

@Component({
  selector: 'app-framework-list',
  standalone: true,
  imports: [FormsModule],
  template: `
    <input
      type="search"
      [(ngModel)]="query"
      placeholder="Filter frameworks…"
      aria-label="Filter frameworks"
    />

    <ul role="list" aria-live="polite" aria-label="Frameworks">
      @for (fw of filtered(); track fw.id) {
        <li>{{ fw.name }} <span>({{ fw.language }})</span></li>
      } @empty {
        <li>No frameworks match your search.</li>
      }
    </ul>

    <p>{{ filtered().length }} of {{ frameworks.length }} shown</p>
  `,
})
export class FrameworkListComponent {
  query = '';

  frameworks: Framework[] = [
    { id: 1, name: 'Angular',   language: 'TypeScript' },
    { id: 2, name: 'React',     language: 'JavaScript' },
    { id: 3, name: 'Vue',       language: 'JavaScript' },
    { id: 4, name: 'Svelte',    language: 'JavaScript' },
    { id: 5, name: 'SolidJS',   language: 'JavaScript' },
    { id: 6, name: 'Blazor',    language: 'C#' },
  ];

  filtered = computed(() => {
    const q = this.query.toLowerCase();
    return this.frameworks.filter(
      fw => fw.name.toLowerCase().includes(q)
    );
  });
}

// framework-list.component.spec.ts
import { ComponentFixture, TestBed } from '@angular/core/testing';
import { FrameworkListComponent } from './framework-list.component';
import { By } from '@angular/platform-browser';

describe('FrameworkListComponent', () => {
  let fixture: ComponentFixture<FrameworkListComponent>;
  let component: FrameworkListComponent;

  beforeEach(async () => {
    await TestBed.configureTestingModule({
      imports: [FrameworkListComponent],
    }).compileComponents();

    fixture = TestBed.createComponent(FrameworkListComponent);
    component = fixture.componentInstance;
    fixture.detectChanges();
  });

  it('renders all frameworks by default', () => {
    const items = fixture.debugElement.queryAll(By.css('li'));
    // 6 frameworks + no @empty branch
    expect(items.length).toBe(6);
  });

  it('filters by query', () => {
    component.query = 'ang';
    fixture.detectChanges();

    const items = fixture.debugElement.queryAll(By.css('li'));
    expect(items.length).toBe(1);
    expect(items[0].nativeElement.textContent).toContain('Angular');
  });

  it('shows empty message when no results match', () => {
    component.query = 'zzznomatch';
    fixture.detectChanges();

    const items = fixture.debugElement.queryAll(By.css('li'));
    expect(items.length).toBe(1);
    expect(items[0].nativeElement.textContent).toContain('No frameworks');
  });
});
